// ═══════════════════════════════════════════════════════════════
// 🧹 LIMPIAR RESPUESTA + FALLBACK ante falla del AI Agent
// ═══════════════════════════════════════════════════════════════

// Detectar si el AI Agent falló (continueOnFail propagates error)
const aiOutput = $input.first();
const hasError = aiOutput?.json?.error || !aiOutput?.json?.output;

if (hasError) {
  const errorMsg = aiOutput?.json?.error?.message || aiOutput?.json?.errorMessage || 'AI Agent failed';
  console.log(`🚨 AI Agent ERROR: ${errorMsg}`);

  // FIX: Don't send error message to patient — stop flow instead
  // Sending "dificultades técnicas" destroys trust. Better to send nothing.
  console.log('🛑 AI Agent failed — stopping flow (no message sent to patient)');
  return [];
}

// ── Normal flow: clean the AI response ──
const raw = (aiOutput.json.output || aiOutput.json.text || aiOutput.json.response || '').trim();

if (!raw) {
  console.log('🛑 AI Agent returned empty response — stopping flow');
  return [];
}

// Clean WhatsApp formatting artifacts
let cleaned = raw
  .replace(/\*\*([^*]+)\*\*/g, '*$1*')  // **bold** → *bold*
  .replace(/^#+\s*/gm, '')                 // Remove markdown headers
  .replace(/```[\s\S]*?```/g, '')          // Remove code blocks
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1') // [text](url) → text
  .replace(/\n{3,}/g, '\n\n')              // Max 2 newlines
  .trim();

// Truncate if too long for WhatsApp
if (cleaned.length > 4000) {
  cleaned = cleaned.substring(0, 3900) + '\n\n_Le envío el resto en un momento..._';
}

return [{ json: { text: cleaned, is_fallback: false } }];

// ═══════════════════════════════════════════════════════════════
// 7️⃣ PROCESAR ANÁLISIS V3 — Simplified (CRM-only)
// ═══════════════════════════════════════════════════════════════

const ctx = $('5️⃣ Procesar Contexto').first()?.json || {};
const rawOutput = $input.first()?.json?.text || $input.first()?.json?.output || '';

let analisis = {};
try {
  const cleaned = rawOutput.replace(/```json\n?|```\n?/g, '').trim();
  analisis = JSON.parse(cleaned);
} catch (e) {
  try {
    const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) analisis = JSON.parse(jsonMatch[0]);
  } catch (e2) {
    analisis = {};
  }
}

// Fallback defaults
if (!analisis.intencion_principal) {
  analisis = {
    intencion_principal: 'otro',
    tema_detectado: 'general',
    perfil_paciente: 'solo_curiosidad',
    sentimiento: 'neutro',
    barrera_principal: 'ninguna',
    pregunto_precio: false,
    senales_precio: { pregunto_precio: false, menciono_presupuesto: false, nivel_sensibilidad: 'ninguna' },
    sintomas_estructurados: [],
    banderas_rojas: [],
    urgencia_percibida: 'normal',
    nombre_detectado: null,
    edad_detectada: null,
    para_quien: 'para_si_mismo'
  };
}

// === EXTRACT FIELDS ===
const intencionPrincipal = analisis.intencion_principal || 'otro';
const temaDetectado = analisis.tema_detectado || 'general';
const perfilPaciente = analisis.perfil_paciente || 'solo_curiosidad';
const sentimiento = analisis.sentimiento || 'neutro';
const barrieraPrincipal = analisis.barrera_principal || 'ninguna';

// === PRECIO (ACUMULATIVO) ===
const senalesPrecio = analisis.senales_precio || {};
const preguntoPrecioNuevo = senalesPrecio.pregunto_precio || analisis.pregunto_precio || false;
const preguntoPrecio = preguntoPrecioNuevo || ctx.pregunto_precio || false;
const nivelSensibilidadPrecio = senalesPrecio.nivel_sensibilidad || 'ninguna';

// === NOMBRE (anti-síntoma validation) ===
const terminosMedicos = new Set([
  'disuria', 'hematuria', 'polaquiuria', 'nicturia', 'incontinencia',
  'fimosis', 'prostatitis', 'cistitis', 'varicocele', 'hidrocele',
  'dolor', 'ardor', 'sangre', 'piedra', 'riñon', 'prostata', 'próstata',
  'hola', 'buenos', 'dias', 'buenas', 'tardes', 'noches', 'gracias',
  'ok', 'si', 'sí', 'no', 'claro', 'dale', 'perfecto', 'bien'
]);
const rawNombre = analisis.nombre_detectado || null;
const nombreDetectado = (rawNombre && !terminosMedicos.has(rawNombre.toLowerCase().trim()) && rawNombre.length > 1 && rawNombre.length < 60) ? rawNombre : null;

// === URGENCIA (NEVER DOWNGRADE) ===
const urgenciaNueva = analisis.urgencia_percibida || 'normal';
const urgenciaPrevia = ctx.urgencia_percibida || 'normal';
const ordenUrgencia = { 'normal': 1, 'alta': 2, 'emergencia': 3 };
const urgenciaFinal = (ordenUrgencia[urgenciaNueva] || 1) >= (ordenUrgencia[urgenciaPrevia] || 1) ? urgenciaNueva : urgenciaPrevia;

// === SÍNTOMAS (merge with previous, no duplicates) ===
const sintomasNuevos = Array.isArray(analisis.sintomas_estructurados)
  ? analisis.sintomas_estructurados.filter(s => s && s.nombre)
  : [];

let sintomasPrevios = [];
if (Array.isArray(ctx.sintomas_acumulados)) {
  sintomasPrevios = ctx.sintomas_acumulados.map(s => typeof s === 'string' ? { nombre: s, severidad: 'moderada' } : s);
}

const ordenSeveridad = { 'leve': 1, 'moderada': 2, 'severa': 3 };
const sintomasMerged = [...sintomasPrevios];
for (const sNew of sintomasNuevos) {
  const nombreLower = (sNew.nombre || '').toLowerCase();
  const existente = sintomasMerged.find(s => (s.nombre || '').toLowerCase() === nombreLower);
  if (!existente) {
    sintomasMerged.push(sNew);
  } else {
    if ((ordenSeveridad[sNew.severidad] || 2) > (ordenSeveridad[existente.severidad] || 2)) {
      existente.severidad = sNew.severidad;
    }
    if (sNew.descripcion_original) existente.descripcion_original = sNew.descripcion_original;
    if (!existente.tiempo_evolucion && sNew.tiempo_evolucion) existente.tiempo_evolucion = sNew.tiempo_evolucion;
  }
}

// === BANDERAS ROJAS (ACUMULATIVAS) ===
const banderasNuevas = Array.isArray(analisis.banderas_rojas) ? analisis.banderas_rojas : [];
const banderasPrevias = Array.isArray(ctx.banderas_rojas_previas) ? ctx.banderas_rojas_previas : [];
const banderasMerged = [...new Set([...banderasPrevias, ...banderasNuevas])];

return [{
  json: {
    ...ctx,
    // CRM fields
    intencion_principal: intencionPrincipal,
    intencion: intencionPrincipal,
    tema_detectado: temaDetectado,
    perfil_paciente: perfilPaciente,
    sentimiento,
    barrera_principal: barrieraPrincipal,
    senales_precio: senalesPrecio,
    nivel_sensibilidad_precio: nivelSensibilidadPrecio,
    pregunto_precio: preguntoPrecio,
    para_quien: analisis.para_quien || 'para_si_mismo',
    edad_detectada: analisis.edad_detectada || null,
    nombre_detectado: nombreDetectado,
    urgencia_percibida: urgenciaFinal,
    es_urgencia_medica: urgenciaFinal === 'emergencia' || urgenciaFinal === 'alta',
    sintomas_estructurados: sintomasMerged,
    sintomas_merged: sintomasMerged.map(s => s.nombre).filter(Boolean),
    banderas_rojas: banderasMerged,
    tiene_historial_real: (ctx.historial_mensajes || '').length > 50,
    es_primera_interaccion: !((ctx.historial_mensajes || '').length > 50) && (ctx.total_mensajes || 0) <= 1
  }
}];

// ═══════════════════════════════════════════════════════════════════
// 🏷️ CLASIFICADOR HÍBRIDO UROBOT v2 - TÚ + USTED + multi-line
// ═══════════════════════════════════════════════════════════════════

const ctx = $('9️⃣ Formatear Contexto').first()?.json || {};
const limpioData = $('🧹 Limpiar Respuesta').first()?.json || {};
const texto = limpioData.text || '';
const t = texto.toLowerCase();
const parrafos = texto.split(/\n\n+/).filter(p => p.trim());
const ultimoParrafo = (parrafos[parrafos.length - 1] || texto).toLowerCase();
// Texto completo sin saltos de línea para regex multi-line
const tFlat = t.replace(/\n/g, ' ');

function clasificarHibrido() {
  // ── PASO 1: CONFIRMACIÓN de cita (alta prioridad) ──
  // Bot confirma que la cita quedó agendada/reservada
  if (/qued(ó|a)?\s*(agendad|reservad|formalmente)|ya qued(ó|a)|su cita.*confirm|tu cita.*confirm|listo.*reserv|queda reservad/i.test(t)) return 'confirmacion';
  // Bot pide nombre completo para agendar
  if (/confirm(a|e)me (tu|su) nombre|(tu|su) nombre completo|para (generar|abrir).*expediente|necesito su nombre/i.test(t)) return 'confirmacion';

  // ── PASO 2: HORARIOS DADOS (bot mostró disponibilidad real) ──
  // Detecta días + horas en el texto (multi-line safe con tFlat)
  if (/(lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado)[\s\S]{0,60}\d{1,2}[:\.]?\d{0,2}\s*(hrs|hr|pm|am|p\.m|a\.m)?/i.test(tFlat)) {
    // Si además hay pregunta = pidiendo que elija horario
    if (/\?/.test(t)) return 'horarios_dados';
    // Si menciona "disponible/espacio/tengo" = mostrando opciones
    if (/disponib|espacio|tengo|le queda/i.test(t)) return 'horarios_dados';
  }
  // Patrón directo: hora + pregunta (multi-line safe)
  if (/\d{1,2}:\d{2}\s*(pm|am|hrs|p\.m|a\.m)?[\s\S]{0,80}\?/i.test(tFlat)) return 'horarios_dados';
  // "te/le queda/funciona/parece este horario"
  if (/(te|le) (queda|funciona|parece|acomoda)[\s\S]{0,30}(horario|hora|espacio)|apartarlo|apart[aá]rselo/i.test(tFlat)) return 'horarios_dados';

  // ── PASO 3: OFERTA DE CITA (bot invita a agendar) ──
  // USTED patterns (el bot habla de usted por defecto)
  if (/le (busco|consigo|agendo|aparto)\s*(un\s*)?(espacio|horario|cita|lugar)/i.test(t)) return 'oferta_cita';
  if (/le (gustar[ií]a|interesa)\s*(que le)?\s*(busque|agende|aparte|consiga)/i.test(t)) return 'oferta_cita';
  if (/le queda mejor.*(polanco|sat[eé]lite|sede)|cu[aá]l sede le/i.test(t)) return 'oferta_cita';
  if (/en cu[aá]l sede le (acomoda|queda|conviene)/i.test(t)) return 'oferta_cita';
  if (/quiere que le (agende|busque|aparte)/i.test(t)) return 'oferta_cita';
  // TÚ patterns (si el paciente tutea)
  if (/te (gustar[ií]a|interesa).*agendar|te ofrezca.*espacio|quieres.*cita/i.test(t)) return 'oferta_cita';
  // Cierre suave con sede
  if (/polanco o sat[eé]lite/i.test(ultimoParrafo) && /\?/.test(ultimoParrafo)) return 'oferta_cita';

  // ── PASO 4: DESCUBRIMIENTO (pregunta médica) ──
  if (/\?/.test(ultimoParrafo) && /s[ií]ntoma|siente|cu[aá]ndo|molest|orin|dolor|ard|sangr|pr[oó]stat|levant|ba[nñ]o|noche/i.test(ultimoParrafo)) return 'descubrimiento';

  // ── PASO 5: Fallbacks por contenido ──
  if (/recuerda.*cita|no olvides|te esperamos|le esperamos|cualquier.*duda.*(aqu[ií]|estamos)/i.test(t)) return 'seguimiento';
  if (/\$\s*\d|precio|costo|consult.*incluye|honorario|\d[,.]?\d{3}\s*(mxn|pesos)/i.test(t)) {
    if (/disponib|espacio|lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado/i.test(t)) return 'horarios_dados';
    return 'precio_dado';
  }
  if (/ubicaci|direcci|blvd|colonia|consultorio|hospital.*[aá]ngeles|san.*[aá]ngel/i.test(t)) return 'ubicacion_dada';
  if (/urgencia|emergencia|acudir.*inmediatamente|urolog.*guardia/i.test(t)) return 'escalamiento';
  if (/bienvenid|encantado|mucho gusto|soy.*dr|asistente.*dr|qu[eé] gusto que nos escribe/i.test(t)) return 'bienvenida';

  return 'conversacion';
}

const faseConversacion = clasificarHibrido();

// Determinar si el bot espera respuesta
const esperaRespuesta = /\?/.test(ultimoParrafo) || 
  ['descubrimiento', 'horarios_dados', 'oferta_cita', 'confirmacion'].includes(faseConversacion);

// Acción del bot → mapea a valores que transition_lead_estado reconoce
const accionesMap = {
  'informar_vph': 'informar_precio',
  'confirmacion': 'confirmar_cita',
  'horarios_dados': 'mostrar_horarios',
  'oferta_cita': 'ofrecer_cita',
  'descubrimiento': 'evaluar_sintomas',
  'precio_dado': 'informar_precio',
  'ubicacion_dada': 'informar_ubicacion',
  'escalamiento': 'escalar_urgente',
  'seguimiento': 'recordar_cita',
  'bienvenida': 'presentarse',
  'conversacion': 'continuar'
};
const accionBot = accionesMap[faseConversacion] || 'continuar';

return [{
  json: {
    ...ctx,
    text: limpioData.text || '',
    fase_conversacion: faseConversacion,
    accion_bot: accionBot,
    espera_respuesta: esperaRespuesta,
    conversacion_id: ctx.conversacion_id || null
  }
}];

const ctx = $('9️⃣ Formatear Contexto').first()?.json || $('5️⃣ Procesar Contexto').first()?.json || {};
console.log(`⏸️ Anti-Baneo SKIP: ${ctx.telefono || 'desconocido'} - mensaje no enviado por rate limit`);
